document.addEventListener('DOMContentLoaded',()=>{const app={user:null,users:[],roleMap:{patient:'receptionist',doctor:'doctor',lab:'lab_tech',pharmacy:'pharmacist',admin:'admin'},init(){this.cacheDOM();this.loadUser();this.bindEvents();this.showSection('welcome');this.renderUserTable();},cacheDOM(){this.sections=document.querySelectorAll('.content-section');this.modules=document.querySelectorAll('.module');this.navLinks=document.querySelectorAll('.nav-link');this.loginForm=document.getElementById('login-form');this.loginTrigger=document.getElementById('login-trigger');this.profilePic=document.getElementById('profile-pic');this.usernameDisplay=document.getElementById('username-display');this.userProfile=document.getElementById('user-profile');this.logoutBtn=document.getElementById('logout-btn');this.settingsLink=document.getElementById('settings-link');this.settingsForm=document.getElementById('settings-form');this.avatarInput=document.getElementById('settings-avatar');this.addUserForm=document.getElementById('add-user-form');this.userTableBody=document.querySelector('#user-table tbody');this.contactForm=document.getElementById('contact-form');this.adminModule=document.querySelector('.module.admin');},bindEvents(){this.loginForm.addEventListener('submit',e=>{e.preventDefault();const email=document.getElementById('login-email').value;const role=document.getElementById('login-role').value;this.login(email,role);this.loginForm.reset();});this.loginTrigger.addEventListener('click',e=>{e.preventDefault();this.showSection('login');});this.modules.forEach(mod=>{mod.addEventListener('click',()=>{if(!this.user)return this.showSection('login');const section=mod.dataset.section;if(this.user.role===this.roleMap[section]||this.user.role==='admin'){this.showSection(section);}else{alert('Access denied');}});});this.navLinks.forEach(link=>{link.addEventListener('click',e=>{e.preventDefault();const section=link.dataset.section;this.showSection(section);});});this.logoutBtn.addEventListener('click',()=>this.logout());this.profilePic.addEventListener('click',()=>{if(this.user)this.showSection('settings');});this.settingsLink.addEventListener('click',e=>{e.preventDefault();this.showSection('settings');document.getElementById('settings-name').value=this.user.name;document.getElementById('settings-email').value=this.user.email;});this.settingsForm.addEventListener('submit',e=>{e.preventDefault();this.user.name=document.getElementById('settings-name').value;this.user.email=document.getElementById('settings-email').value;this.saveUser();this.updateUI();alert('Profile updated');});this.avatarInput.addEventListener('change',e=>{const file=e.target.files[0];const reader=new FileReader();reader.onload=ev=>{this.user.avatar=ev.target.result;this.profilePic.src=ev.target.result;this.saveUser();};reader.readAsDataURL(file);});this.addUserForm.addEventListener('submit',e=>{e.preventDefault();const name=document.getElementById('new-user-name').value;const email=document.getElementById('new-user-email').value;const role=document.getElementById('new-user-role').value;this.users.push({name,email,role,id:Date.now()});this.addUserForm.reset();this.renderUserTable();});if(this.contactForm){this.contactForm.addEventListener('submit',e=>{e.preventDefault();const name=document.getElementById('contact-name').value;alert(`Thanks for contacting us, ${name}!`);this.contactForm.reset();});}},login(email,role){this.user={email,name:email.split('@')[0],role,avatar:`https://ui-avatars.com/api/?name=${email.split('@')[0]}&background=random`,id:Date.now()};this.saveUser();this.updateUI();this.showSection('welcome');},logout(){this.user=null;localStorage.removeItem('user');this.updateUI();this.showSection('welcome');},loadUser(){const data=localStorage.getItem('user');if(data){this.user=JSON.parse(data);this.updateUI();}},saveUser(){localStorage.setItem('user',JSON.stringify(this.user));},updateUI(){const isLoggedIn=!!this.user;this.userProfile.style.display=isLoggedIn?'flex':'none';this.loginTrigger.style.display=isLoggedIn?'none':'block';if(isLoggedIn){this.usernameDisplay.textContent=this.user.name;this.profilePic.src=this.user.avatar;}this.modules.forEach(mod=>{const section=mod.dataset.section;const hasAccess=isLoggedIn&&(this.user.role===this.roleMap[section]||this.user.role==='admin');mod.classList.toggle('disabled',!hasAccess);mod.style.display=section==='admin'&&this.user.role!=='admin'?'none':'block';});},showSection(id){this.sections.forEach(section=>section.classList.remove('active-content'));const target=document.getElementById(id);if(target)target.classList.add('active-content');},renderUserTable(){this.userTableBody.innerHTML='';this.users.forEach((user,index)=>{const row=document.createElement('tr');row.innerHTML=`<td>${user.name}</td><td>${user.email}</td><td>${user.role}</td><td><button class="edit-btn" data-id="${user.id}">Edit</button><button class="delete-btn" data-id="${user.id}">Delete</button></td>`;this.userTableBody.appendChild(row);});this.addTableEvents();},addTableEvents(){document.querySelectorAll('.edit-btn').forEach(btn=>{btn.addEventListener('click',e=>{const id=parseInt(e.target.dataset.id);this.editUser(id);});});document.querySelectorAll('.delete-btn').forEach(btn=>{btn.addEventListener('click',e=>{const id=parseInt(e.target.dataset.id);this.deleteUser(id);});});},editUser(id){const index=this.users.findIndex(u=>u.id===id);if(index===-1)return;const user=this.users[index];document.getElementById('new-user-name').value=user.name;document.getElementById('new-user-email').value=user.email;document.getElementById('new-user-role').value=user.role;this.users.splice(index,1);this.renderUserTable();},deleteUser(id){if(!confirm('Confirm delete?'))return;const index=this.users.findIndex(u=>u.id===id);if(index===-1)return;this.users.splice(index,1);this.renderUserTable();}};window.app=app;app.init();});